public static Map<Long, Set<Long>> problemSevenSeq(CustomerRepo customerRepo, OrderRepo orderRepo, ProductRepo productRepo) {
    Map<Long, Set<Long>> result = new HashMap<>();

    // Initialize map with all Tech products
    productRepo.findAll().stream()
        .filter(product -> "Tech".equals(product.getCategory()))
        .forEach(product -> result.put(product.getId(), new HashSet<>()));

    // For each order, add customer to Tech products they ordered
    orderRepo.findAll().stream()
        .forEach(order -> {
            Long customerId = order.getCustomer().getId();
            order.getProducts().stream()
                .filter(product -> "Tech".equals(product.getCategory()))
                .forEach(product -> result.get(product.getId()).add(customerId));
        });

    return result;
}

